const fs = require('fs');
const configPath = '/home/node/config/feeds.json';

try {
  const raw = fs.readFileSync(configPath, 'utf-8');
  const config = JSON.parse(raw);
  const defaults = config.defaults || {};
  const templates = config.prompt_templates || {};

  const enabledFeeds = (config.feeds || []).filter(f => f.enabled);

  return enabledFeeds.map(feed => ({
    json: {
      name: feed.name,
      display_name: feed.display_name,
      feed_id: feed.feed_id,
      category: feed.category,
      model: feed.model || defaults.model || 'anthropic/claude-haiku-4.5',
      lookback_hours: feed.lookback_hours || defaults.lookback_hours || 24,
      prompt_template: templates[feed.prompt_template || defaults.prompt_template] || templates['one_line_summary'],
      freshrss_user: feed.freshrss_user || defaults.freshrss_user || process.env.USER || 'owen'
    }
  }));
} catch (err) {
  return [{ json: { error: 'Failed to read feeds.json: ' + err.message, feeds: [] } }];
}

const sqlite3 = require('sqlite3').verbose();
const feed = $input.first().json;
const dbPath = `/freshrss-data/users/${feed.freshrss_user}/db.sqlite`;

return new Promise((resolve) => {
  const db = new sqlite3.Database(dbPath, sqlite3.OPEN_READONLY, (err) => {
    if (err) {
      resolve([{ json: { ...feed, entries: [], error: err.message } }]);
      return;
    }
  });

  const cutoffSeconds = Math.floor(Date.now() / 1000) - feed.lookback_hours * 60 * 60;

  db.all(
    'SELECT title, link, date FROM entry WHERE id_feed = ? AND date > ? ORDER BY date DESC',
    [feed.feed_id, cutoffSeconds],
    (err, rows) => {
      if (err) {
        resolve([{ json: { ...feed, entries: [], error: err.message } }]);
      } else {
        resolve([{ json: { ...feed, entries: rows || [] } }]);
      }
      db.close();
    }
  );
});

const feed = $input.first().json;
const entries = feed.entries;
const date = new Date().toISOString().split('T')[0];

const maxPerBatch = feed.max_articles_per_batch || null;
const maxBatches = feed.max_batches || 10;

if (!maxPerBatch) {
  // No batching — original behavior
  const articleList = entries.map((e, i) => `${i + 1}. ${e.title}`).join('\n');
  let prompt = feed.prompt_template
    .replace(/\{count\}/g, entries.length.toString())
    .replace(/\{display_name\}/g, feed.display_name)
    .replace(/\{article_list\}/g, articleList)
    .replace(/\{date\}/g, date);
  return [{ json: { ...feed, prompt, date, count: entries.length, batch_index: null, total_batches: 1 } }];
}

// Batching mode: split into chunks of maxPerBatch
const batches = [];
for (let i = 0; i < entries.length && batches.length < maxBatches; i += maxPerBatch) {
  batches.push(entries.slice(i, i + maxPerBatch));
}

return batches.map((batchEntries, idx) => {
  const articleList = batchEntries.map((e, i) => `${i + 1}. ${e.title}`).join('\n');
  let prompt = feed.prompt_template
    .replace(/\{count\}/g, batchEntries.length.toString())
    .replace(/\{display_name\}/g, feed.display_name)
    .replace(/\{article_list\}/g, articleList)
    .replace(/\{date\}/g, date);
  return {
    json: {
      ...feed,
      prompt,
      date,
      count: batchEntries.length,
      batch_index: idx + 1,
      total_batches: batches.length
    }
  };
});

// Use .item (not .first()) to get the paired Build Prompt item for this batch
const feed = $('Build Prompt').item.json;
const response = $input.first().json;
const content = response.choices[0].message.content;
const date = feed.date;
const category = feed.category;
const name = feed.name;
const batchIndex = feed.batch_index;

// Add batch suffix for batched feeds (e.g. arxiv_cs_ai_briefing_2026-03-30_batch1.md)
const batchSuffix = batchIndex !== null ? `_batch${batchIndex}` : '';
const filePath = `/home/node/workspace/briefings/${category}/${name}_briefing_${date}${batchSuffix}.md`;

const fs = require('fs');
const dir = `/home/node/workspace/briefings/${category}`;
if (!fs.existsSync(dir)) {
  fs.mkdirSync(dir, { recursive: true });
}

return [{
  json: {
    filePath: filePath,
    content: content,
    feed_name: name,
    category: category,
    date: date,
    batch_index: batchIndex
  }
}];

const data = $input.first().json;
const fs = require('fs');

fs.writeFileSync(data.filePath, data.content, 'utf-8');

return [{
  json: {
    success: true,
    filePath: data.filePath,
    feed_name: data.feed_name,
    category: data.category,
    date: data.date
  }
}];

const feed = $input.first().json;
// Log skipped feed (no articles)
return [{
  json: {
    skipped: true,
    feed_name: feed.name,
    display_name: feed.display_name,
    reason: 'No articles in lookback window'
  }
}];
